- (NSString *)removeEmojisFromString:(NSString *)string {
    if (string.length == 0) {
        return string;
    }

    // 使用正则表达式过滤Emoji表情
    NSString *emojiPattern = @"[\\u2600-\\u26FF\\u2700-\\u27BF\\U0001F000-\\U0001F9FF]";
    NSError *error = nil;
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:emojiPattern
                                                                           options:NSRegularExpressionCaseInsensitive
                                                                             error:&error];
    if (error) {
        NSLog(@"正则表达式错误: %@", error);
        return string;
    }

    NSString *result = [regex stringByReplacingMatchesInString:string
                                                        options:0
                                                          range:NSMakeRange(0, string.length)
                                                   withTemplate:@""];

    return result;
}


