#pragma mark - 网络请求
/*
 使用NSURLSessionDataDelegate和didReceiveData而非completionHandler
 底层差异：
 数据流和缓冲机制的差异：
 NSURLSessionDataDelegate：基于 数据流，数据分批传输到应用层，系统只负责接收，处理逻辑由开发者决定。每个数据块到达时，didReceiveData: 方法被调用，允许你立即处理数据。
 completionHandler：基于 缓冲机制，系统负责将所有数据接收完毕并缓存在本地，只有当全部数据接收完毕后才调用 completionHandler，并将数据一次性提供给应用层。
触发时机的差异：
NSURLSessionDataDelegate：代理方法根据网络传输状态多次触发。每当数据从网络到达时，系统会调用代理方法，开发者可以在这些调用中实时处理数据。
completionHandler：只有在数据完全接收后，才会一次性触发。你无法在数据传输过程中干预或处理部分数据。
 */
- (NSArray *)contextArrayFromJSONString:(NSString *)contextString {
    if (![contextString isKindOfClass:[NSString class]]) {
        return nil;
    }
    NSString *trimmedContext = [contextString stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (trimmedContext.length == 0) {
        return nil;
    }
    NSData *jsonData = [trimmedContext dataUsingEncoding:NSUTF8StringEncoding];
    if (!jsonData) {
        return nil;
    }
