- (void)addSentenceToSpeechQueue:(NSString *)sentence {
    if (!sentence || sentence.length == 0) return;

    // 清理句子中的特殊字符和多余空格
    NSString *cleanSentence = [self cleanSentenceForSpeech:sentence];
    if (cleanSentence.length > 0) {
        [[SpeechManager shared] addSpeechText:cleanSentence];
    }
}

// 清理句子，使其更适合语音合成
- (NSString *)cleanSentenceForSpeech:(NSString *)sentence {
    // 移除多余的空格和换行
    NSString *clean = [sentence stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    // 将多个连续空格替换为单个空格
    clean = [clean stringByReplacingOccurrencesOfString:@"\\s+" withString:@" " options:NSRegularExpressionSearch range:NSMakeRange(0, clean.length)];

    // 移除可能影响语音合成的特殊字符
    NSCharacterSet *specialChars = [NSCharacterSet characterSetWithCharactersInString:@"*#@$%^&<>"];
    clean = [[clean componentsSeparatedByCharactersInSet:specialChars] componentsJoinedByString:@""];

    return clean;
}

- (void)pauseSpeech {
    [[SpeechManager shared].synthesizer pauseSpeakingAtBoundary:AVSpeechBoundaryWord];
}

- (void)resumeSpeech {
    [[SpeechManager shared].synthesizer continueSpeaking];
}

- (void)stopSpeech {
    [[SpeechManager shared] clearQueue];
}

- (void)skipCurrentSpeech {
    SpeechManager *manager = [SpeechManager shared];
    [manager.synthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
}

- (NSString *)removeEmojisFromString:(NSString *)string {
    if (string.length == 0) {
        return string;
    }

    // 使用正则表达式过滤Emoji表情
    NSString *emojiPattern = @"[\\u2600-\\u26FF\\u2700-\\u27BF\\U0001F000-\\U0001F9FF]";
    NSError *error = nil;
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:emojiPattern
                                                                           options:NSRegularExpressionCaseInsensitive
                                                                             error:&error];
    if (error) {
        NSLog(@"正则表达式错误: %@", error);
        return string;
    }

    NSString *result = [regex stringByReplacingMatchesInString:string
                                                        options:0
                                                          range:NSMakeRange(0, string.length)
                                                   withTemplate:@""];

    return result;
}


