#import "SpeechManager.h"

@interface SpeechManager () 
@property (nonatomic, strong) SFSpeechRecognizer *recognizer;
@property (nonatomic, strong) AVAudioEngine *audioEngine;
@property (nonatomic, strong) SFSpeechAudioBufferRecognitionRequest *request;
@property (nonatomic, strong) SFSpeechRecognitionTask *task;

@property (nonatomic, copy) NSString *lastText;
@property (nonatomic, strong) dispatch_source_t textStableSource;

@property (nonatomic, copy) void(^textCallback)(NSString *);
@end

@implementation SpeechManager

+ (instancetype)shared {
    static SpeechManager *manager;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        manager = [[SpeechManager alloc] init];
    });
    return manager;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        NSLocale *locale = [[NSLocale alloc] initWithLocaleIdentifier:@"zh_CN"];
        self.recognizer = [[SFSpeechRecognizer alloc] initWithLocale:locale];
        self.recognizer.delegate = self;
        self.audioEngine = [[AVAudioEngine alloc] init];

        _speechQueue = [NSMutableArray array];
        _synthesizer = [[AVSpeechSynthesizer alloc] init];
        _synthesizer.delegate = self;
        _isSpeaking = NO;
        _volume = 1.0;
    }
    return self;
}

- (void)startRecognize:(void(^)(NSString *text))callback {

    self.textCallback = callback;

    // 请求权限
    [SFSpeechRecognizer requestAuthorization:^(SFSpeechRecognizerAuthorizationStatus status) {
        if (status != SFSpeechRecognizerAuthorizationStatusAuthorized) return;

        dispatch_async(dispatch_get_main_queue(), ^{
            [self startSession];
        });
    }];
}

- (void)startSession {

    [self stopRecognize]; // 如果之前在识别，先停止

    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
    NSError *error = nil;

    // 设置支持后台播放的音频会话类别
    AVAudioSession *session = [AVAudioSession sharedInstance];
    [session setCategory:AVAudioSessionCategoryPlayAndRecord
             withOptions:AVAudioSessionCategoryOptionDefaultToSpeaker
                   error:nil];
    [session setActive:YES error:nil];

    if (error) {
        NSLog(@"音频会话设置出错: %@", error);
    } else {
        // 激活音频会话
        [audioSession setActive:YES withOptions:AVAudioSessionSetActiveOptionNotifyOthersOnDeactivation error:&error];
        if (error) {
            NSLog(@"音频会话激活出错: %@", error);
        }
    }


    self.request = [[SFSpeechAudioBufferRecognitionRequest alloc] init];
    self.request.shouldReportPartialResults = YES;

    AVAudioInputNode *inputNode = self.audioEngine.inputNode;
    AVAudioFormat *format = [inputNode outputFormatForBus:0];

    if (format.sampleRate <= 0 || format.channelCount == 0) {
        NSLog(@"❌ Invalid input format: sampleRate=%f, channels=%lu", format.sampleRate, (unsigned long)format.channelCount);
        return;
    }

    // 监听麦克风
    [inputNode installTapOnBus:0 bufferSize:1024 format:format
                         block:^(AVAudioPCMBuffer *buffer, AVAudioTime *when) {
        [self.request appendAudioPCMBuffer:buffer];
    }];

    [self.audioEngine prepare];
    [self.audioEngine startAndReturnError:nil];

    __weak typeof(self) weakSelf = self;
    self.task = [self.recognizer recognitionTaskWithRequest:self.request
                                              resultHandler:^(SFSpeechRecognitionResult *result, NSError *error) {

        if (result) {
            NSString *text = result.bestTranscription.formattedString;
            if (![text isEqualToString:weakSelf.lastText] && ![text isEqualToString:@""]) {
                // 取消之前的检测任务
                if (weakSelf.textStableSource) {
                    dispatch_source_cancel(weakSelf.textStableSource);
                }
                weakSelf.lastText = text;

                // 创建新的 GCD 定时器
                weakSelf.textStableSource = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, dispatch_get_main_queue());

                dispatch_source_set_timer(weakSelf.textStableSource,
                                        dispatch_time(DISPATCH_TIME_NOW, 1 * NSEC_PER_SEC),
                                        DISPATCH_TIME_FOREVER, 0);

                dispatch_source_set_event_handler(weakSelf.textStableSource, ^{
                    NSLog(@"文本稳定: %@", text);
                    if (weakSelf.textCallback) {
                        weakSelf.textCallback(text);
                    }
                    dispatch_source_cancel(weakSelf.textStableSource);
                });

                dispatch_resume(weakSelf.textStableSource);
            }

//            if (weakSelf.textCallback) {
//                weakSelf.textCallback(text);
//            }
        }

        if (error || (result && result.isFinal)) {
            dispatch_async(dispatch_get_main_queue(), ^{
                [weakSelf stopRecognize];
            });
        }
    }];
}

- (void)stopRecognize {

    if (self.task) {
        [self.task cancel];
        self.task = nil;
    }

    if (self.audioEngine.running) {
        [self.audioEngine stop];
        [self.audioEngine.inputNode removeTapOnBus:0];
    }

    self.request = nil;
}

- (void)addSpeechText:(NSString *)text {
    if (!text || text.length == 0) return;

    // 将文本加入队列
    [self.speechQueue addObject:text];

    // 如果当前没有在朗读，开始朗读
    if (!self.isSpeaking) {
        [self speakNext];
    }
}

- (void)speakNext {
    if (self.speechQueue.count == 0) {
        self.isSpeaking = NO;
        return;
    }

    self.isSpeaking = YES;
    NSString *text = self.speechQueue.firstObject;


    // 创建语音合成器
    AVSpeechUtterance *utterance = [AVSpeechUtterance speechUtteranceWithString:text];
    utterance.rate = AVSpeechUtteranceDefaultSpeechRate;  // 语速
    utterance.pitchMultiplier = 1.0;  // 音调
    utterance.volume = _volume;  // 音量

    AVSpeechSynthesisVoice *voice = [AVSpeechSynthesisVoice voiceWithLanguage:@"en-US"];
    if (voice) {
        utterance.voice = voice;
    }

    [self.synthesizer speakUtterance:utterance];
}

- (void)clearQueue {
    [self.speechQueue removeAllObjects];
    if (self.isSpeaking) {
        [self.synthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }
}

- (void)silence {
    self.volume = 0.0;
}

- (void)sound {
    self.volume = 1.0;
}

#pragma mark - AVSpeechSynthesizerDelegate

- (void)speechSynthesizer:(AVSpeechSynthesizer *)synthesizer didFinishSpeechUtterance:(AVSpeechUtterance *)utterance {
    // 移除已完成的语音
    if (self.speechQueue.count > 0) {
        [self.speechQueue removeObjectAtIndex:0];
    }

    // 播放下一个
    [self speakNext];
}

- (void)speechSynthesizer:(AVSpeechSynthesizer *)synthesizer didCancelSpeechUtterance:(AVSpeechUtterance *)utterance {
    [self speakNext];
}

@end

